const TABS = [
  { key: "all", label: "전체 합산", icon: "📊" },
  { key: "blog", label: "블로그", icon: "📝" },
  { key: "insta", label: "인스타", icon: "📸" },
  { key: "thread", label: "스레드", icon: "🧵" },
  { key: "store", label: "서점 리뷰", icon: "🏪" },
];

const PL = {
  blog: { label: "블로그", color: "#03C75A", icon: "📝" },
  insta: { label: "인스타", color: "#E1306C", icon: "📸" },
  thread: { label: "스레드", color: "#000", icon: "🧵" },
  sarak: { label: "사락", color: "#FF9800", icon: "📖" },
  other: { label: "기타", color: "#666", icon: "🔗" },
};

const Badge = ({ color, children }) => <span style={{ background: color, color: "#fff", padding: "2px 8px", borderRadius: 10, fontSize: 10, fontWeight: 700, whiteSpace: "nowrap" }}>{children}</span>;
const Stars = ({ n }) => <span>{[1,2,3].map(i => <span key={i} style={{ opacity: i <= n ? 1 : 0.15, fontSize: 14 }}>⭐</span>)}</span>;

function StatBox({ value, label, color, onClick, active }) {
  return <div onClick={onClick} style={{ background: active ? color : "#fff", borderRadius: 10, padding: "12px 6px", textAlign: "center", boxShadow: "0 1px 3px rgba(0,0,0,0.05)", cursor: onClick ? "pointer" : "default", border: active ? "none" : "1px solid #f0f0f0", transition: "all 0.15s" }}>
    <div style={{ fontSize: 22, fontWeight: 900, color: active ? "#fff" : color }}>{value}</div>
    <div style={{ fontSize: 9, color: active ? "rgba(255,255,255,0.8)" : "#999", fontWeight: 600, marginTop: 2 }}>{label}</div>
  </div>;
}

function Card({ p, tab, exp, onToggle, chk, onChk }) {
  const gu = (t) => p.platforms.find(x => x.type === t)?.urls || [];
  const bu = gu("blog"), iu = gu("insta"), tu = gu("thread");
  const ds = tab === "store" ? p.reviewScore : tab === "blog" ? bu.length : tab === "insta" ? iu.length : tab === "thread" ? tu.length : p.totalScore;
  const sc = ds >= 3 ? "#2E7D32" : ds >= 2 ? "#FF9800" : ds >= 1 ? "#66BB6A" : "#ccc";

  return <div style={{ background: chk ? "#F7F7F7" : "#fff", borderRadius: 12, marginBottom: 6, boxShadow: chk ? "none" : "0 1px 4px rgba(0,0,0,0.06)", opacity: chk ? 0.55 : 1, transition: "all 0.15s", overflow: "hidden", borderLeft: `4px solid ${sc}` }}>
    <div onClick={onToggle} style={{ padding: "11px 12px", cursor: "pointer", display: "flex", alignItems: "center", gap: 8 }}>
      <input type="checkbox" checked={chk} onChange={e => { e.stopPropagation(); onChk(); }} onClick={e => e.stopPropagation()} style={{ width: 16, height: 16, accentColor: "#2E7D32", flexShrink: 0 }} />
      <span style={{ fontSize: 14, fontWeight: 800, color: "#1a1a2e", minWidth: 52 }}>{p.name}</span>
      <div style={{ display: "flex", gap: 3, flex: 1, flexWrap: "wrap", minWidth: 0 }}>
        {tab === "all" && p.platforms.map((pl, i) => <Badge key={i} color={PL[pl.type]?.color || "#666"}>{PL[pl.type]?.icon} {pl.urls.length > 1 ? pl.urls.length : ""}</Badge>)}
        {tab === "all" && p.reviewScore > 0 && <Badge color="#2E7D32">🏪 {p.reviewScore}</Badge>}
        {tab === "store" && <Stars n={p.reviewScore} />}
        {tab === "blog" && bu.length > 0 && <Badge color="#03C75A">{bu.length}개</Badge>}
        {tab === "insta" && iu.length > 0 && <Badge color="#E1306C">{iu.length}개</Badge>}
        {tab === "thread" && tu.length > 0 && <Badge color="#000">{tu.length}개</Badge>}
      </div>
      <div style={{ background: sc, color: "#fff", borderRadius: 8, padding: "3px 10px", fontWeight: 900, fontSize: 16, minWidth: 28, textAlign: "center", flexShrink: 0 }}>{ds}</div>
      <span style={{ fontSize: 10, color: "#ccc", flexShrink: 0 }}>{exp ? "▲" : "▼"}</span>
    </div>
    {exp && <div style={{ padding: "0 12px 14px", borderTop: "1px solid #f5f5f5" }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginTop: 10, fontSize: 11 }}>
        <div><span style={{ color: "#aaa" }}>전화번호</span><br/><b style={{ fontFamily: "monospace" }}>{p.phone}</b></div>
        <div><span style={{ color: "#aaa" }}>SNS유형</span><br/><b>{p.snsType?.replace(/\|/g, " · ")}</b></div>
      </div>
      <div style={{ marginTop: 6, fontSize: 11 }}><span style={{ color: "#aaa" }}>배송주소</span><br/><span style={{ fontSize: 10 }}>{p.address}</span></div>
      <div style={{ display: "flex", gap: 8, marginTop: 12, padding: "10px", background: "#FAFBFC", borderRadius: 8 }}>
        {[{ v: p.snsCount, l: "서평", c: "#2F5496" }, { v: p.reviewScore, l: "서점리뷰", c: p.reviewScore >= 3 ? "#2E7D32" : p.reviewScore > 0 ? "#FF9800" : "#E1306C" }, { v: p.totalScore, l: "총점", c: "#1a1a2e" }].map((s, i) => <div key={i} style={{ flex: 1, textAlign: "center" }}><div style={{ fontSize: 20, fontWeight: 900, color: s.c }}>{s.v}</div><div style={{ fontSize: 9, color: "#999" }}>{s.l}</div></div>)}
      </div>
      {(tab === "all" || tab === "blog") && bu.length > 0 && <div style={{ marginTop: 10 }}><div style={{ fontSize: 11, fontWeight: 700, color: "#03C75A", marginBottom: 4 }}>📝 블로그</div>{bu.map((u, i) => <a key={i} href={u} target="_blank" rel="noopener noreferrer" style={{ display: "block", fontSize: 10, color: "#03C75A", textDecoration: "none", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", lineHeight: 1.8 }}>{u}</a>)}</div>}
      {(tab === "all" || tab === "insta") && iu.length > 0 && <div style={{ marginTop: 8 }}><div style={{ fontSize: 11, fontWeight: 700, color: "#E1306C", marginBottom: 4 }}>📸 인스타</div>{iu.map((u, i) => <a key={i} href={u} target="_blank" rel="noopener noreferrer" style={{ display: "block", fontSize: 10, color: "#E1306C", textDecoration: "none", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", lineHeight: 1.8 }}>{u}</a>)}</div>}
      {(tab === "all" || tab === "thread") && tu.length > 0 && <div style={{ marginTop: 8 }}><div style={{ fontSize: 11, fontWeight: 700, color: "#000", marginBottom: 4 }}>🧵 스레드</div>{tu.map((u, i) => <a key={i} href={u} target="_blank" rel="noopener noreferrer" style={{ display: "block", fontSize: 10, color: "#333", textDecoration: "none", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", lineHeight: 1.8 }}>{u}</a>)}</div>}
      {(tab === "all" || tab === "store") && p.reviewImages.length > 0 && <div style={{ marginTop: 10 }}><div style={{ fontSize: 11, fontWeight: 700, color: "#2E7D32", marginBottom: 4 }}>🏪 서점 리뷰 인증 ({p.reviewImages.length}곳)</div><div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>{p.reviewImages.map((img, i) => <a key={i} href={img} target="_blank" rel="noopener noreferrer" style={{ padding: "5px 10px", background: "#E8F5E9", borderRadius: 6, fontSize: 10, color: "#2E7D32", textDecoration: "none", fontWeight: 700 }}>📋 서점{i + 1}</a>)}</div></div>}
      {(tab === "all" || tab === "store") && p.reviewScore === 0 && <div style={{ marginTop: 10, padding: "6px 10px", background: "#FFF3E0", borderRadius: 6, fontSize: 10, color: "#E65100", fontWeight: 600 }}>⚠️ 서점 리뷰 미제출</div>}
    </div>}
  </div>;
}

export default function App() {
  const [chk, setChk] = useState({});
  const [exp, setExp] = useState({});
  const [tab, setTab] = useState("all");
  const [search, setSearch] = useState("");
  const [rf, setRf] = useState("all");

  useEffect(() => { try { const s = localStorage.getItem("rv2"); if (s) setChk(JSON.parse(s)); } catch(e) {} }, []);
  const save = (c) => { try { localStorage.setItem("rv2", JSON.stringify(c)); } catch(e) {} };
  const toggle = (k) => { const c = { ...chk, [k]: !chk[k] }; if (!c[k]) delete c[k]; setChk(c); save(c); };

  const filtered = (() => {
    let d = [...DATA];
    if (tab === "blog") d = d.filter(p => p.platforms.some(x => x.type === "blog"));
    if (tab === "insta") d = d.filter(p => p.platforms.some(x => x.type === "insta"));
    if (tab === "thread") d = d.filter(p => p.platforms.some(x => x.type === "thread"));
    if (tab === "store") { if (rf === "3") d = d.filter(p => p.reviewScore >= 3); else if (rf === "2") d = d.filter(p => p.reviewScore === 2); else if (rf === "1") d = d.filter(p => p.reviewScore === 1); else if (rf === "0") d = d.filter(p => p.reviewScore === 0); }
    if (search) d = d.filter(p => p.name.includes(search));
    d.sort((a, b) => { if (tab === "store") return b.reviewScore - a.reviewScore; return b.totalScore - a.totalScore; });
    return d;
  })();

  const bc = DATA.filter(p => p.platforms.some(x => x.type === "blog")).length;
  const ic = DATA.filter(p => p.platforms.some(x => x.type === "insta")).length;
  const tc = DATA.filter(p => p.platforms.some(x => x.type === "thread")).length;
  const s3 = DATA.filter(p => p.reviewScore >= 3).length;
  const s2 = DATA.filter(p => p.reviewScore === 2).length;
  const s1 = DATA.filter(p => p.reviewScore === 1).length;
  const s0 = DATA.filter(p => p.reviewScore === 0).length;

  return <div style={{ fontFamily: "'Noto Sans KR', -apple-system, sans-serif", background: "#F8F9FB", minHeight: "100vh" }}>
    <div style={{ maxWidth: 720, margin: "0 auto", padding: "16px 12px" }}>
      <h1 style={{ fontSize: 18, fontWeight: 900, color: "#1a1a2e", margin: 0 }}>📖 완벽한 원시인 서평단</h1>
      <p style={{ color: "#bbb", fontSize: 10, margin: "2px 0 14px" }}>93명 · 서평 + 서점리뷰 종합 관리</p>
      <div style={{ display: "flex", gap: 4, marginBottom: 14, overflowX: "auto" }}>
        {TABS.map(t => <button key={t.key} onClick={() => { setTab(t.key); setRf("all"); }} style={{ padding: "8px 14px", borderRadius: 10, border: "none", fontSize: 12, fontWeight: 700, cursor: "pointer", whiteSpace: "nowrap", background: tab === t.key ? "#1a1a2e" : "#fff", color: tab === t.key ? "#fff" : "#666", boxShadow: tab === t.key ? "0 2px 8px rgba(0,0,0,0.15)" : "0 1px 2px rgba(0,0,0,0.05)" }}>{t.icon} {t.label}</button>)}
      </div>
      {tab === "all" && <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 6, marginBottom: 14 }}>
        <StatBox value={DATA.length} label="전체" color="#1a1a2e" />
        <StatBox value={bc} label="블로그" color="#03C75A" />
        <StatBox value={ic} label="인스타" color="#E1306C" />
        <StatBox value={`${s3+s2}/${DATA.length}`} label="리뷰2곳↑" color="#2E7D32" />
      </div>}
      {tab === "blog" && <div style={{ background: "#fff", borderRadius: 10, padding: 14, marginBottom: 14, boxShadow: "0 1px 3px rgba(0,0,0,0.05)" }}><div style={{ fontSize: 13, fontWeight: 800, color: "#03C75A" }}>📝 블로그 서평 {bc}명</div></div>}
      {tab === "insta" && <div style={{ background: "#fff", borderRadius: 10, padding: 14, marginBottom: 14, boxShadow: "0 1px 3px rgba(0,0,0,0.05)" }}><div style={{ fontSize: 13, fontWeight: 800, color: "#E1306C" }}>📸 인스타 서평 {ic}명</div></div>}
      {tab === "thread" && <div style={{ background: "#fff", borderRadius: 10, padding: 14, marginBottom: 14, boxShadow: "0 1px 3px rgba(0,0,0,0.05)" }}><div style={{ fontSize: 13, fontWeight: 800, color: "#000" }}>🧵 스레드 서평 {tc}명</div></div>}
      {tab === "store" && <>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 6, marginBottom: 10 }}>
          <StatBox value={s3} label="3곳 ⭐⭐⭐" color="#2E7D32" onClick={() => setRf(rf === "3" ? "all" : "3")} active={rf === "3"} />
          <StatBox value={s2} label="2곳 ⭐⭐" color="#FF9800" onClick={() => setRf(rf === "2" ? "all" : "2")} active={rf === "2"} />
          <StatBox value={s1} label="1곳 ⭐" color="#FFB74D" onClick={() => setRf(rf === "1" ? "all" : "1")} active={rf === "1"} />
          <StatBox value={s0} label="미제출" color="#E1306C" onClick={() => setRf(rf === "0" ? "all" : "0")} active={rf === "0"} />
        </div>
        <div style={{ background: "#fff", borderRadius: 10, padding: "10px 14px", marginBottom: 14, boxShadow: "0 1px 3px rgba(0,0,0,0.05)" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}><span style={{ fontSize: 12, fontWeight: 700 }}>🏪 제출률</span><span style={{ fontSize: 14, fontWeight: 900, color: "#2E7D32" }}>{Math.round((DATA.length - s0) / DATA.length * 100)}%</span></div>
          <div style={{ background: "#eee", borderRadius: 4, height: 8, marginTop: 6, overflow: "hidden" }}><div style={{ display: "flex", height: "100%" }}><div style={{ width: `${s3/DATA.length*100}%`, background: "#2E7D32" }} /><div style={{ width: `${s2/DATA.length*100}%`, background: "#FF9800" }} /><div style={{ width: `${s1/DATA.length*100}%`, background: "#FFB74D" }} /></div></div>
        </div>
      </>}
      <input type="text" placeholder="이름 검색..." value={search} onChange={e => setSearch(e.target.value)} style={{ width: "100%", padding: "9px 12px", borderRadius: 10, border: "1px solid #e8e8e8", fontSize: 12, marginBottom: 10, boxSizing: "border-box", outline: "none" }} />
      <div style={{ fontSize: 11, color: "#999", marginBottom: 8 }}>{filtered.length}명 · 체크 {Object.keys(chk).length}/{DATA.length}</div>
      {filtered.map(p => <Card key={p.name+p.phone} p={p} tab={tab} exp={!!exp[p.name+p.phone]} onToggle={() => setExp(v => ({...v, [p.name+p.phone]: !v[p.name+p.phone]}))} chk={!!chk[p.name+p.phone]} onChk={() => toggle(p.name+p.phone)} />)}
      <div style={{ textAlign: "center", marginTop: 20, paddingBottom: 40 }}><button onClick={() => { if(confirm("초기화?")) { setChk({}); localStorage.removeItem("rv2"); }}} style={{ padding: "7px 18px", borderRadius: 8, border: "1px solid #ddd", background: "#fff", color: "#aaa", fontSize: 10, cursor: "pointer" }}>초기화</button></div>
    </div>
  </div>;
}
